/**
 * A minimal valid silent MP3 frame, base64-encoded.
 *
 * Used as the placeholder `automatic_audio_output` data when creating a bot so
 * that Recall's on-demand `output_audio` endpoint is unlocked. The placeholder
 * plays a brief moment of silence when the bot enters the recording state; the
 * real audio is sent later via `POST /bot/{id}/output_audio/`.
 *
 * This is a single MPEG-1 Layer III frame at 128 kbps, 44.1 kHz, stereo. The
 * frame data is all zeros (silence). Total size: 417 bytes.
 */
export const SILENT_MP3_B64 =
  "";
